# --- PyTorch DL Model Architecture (Part 2) ---
class RecommenderNet(nn.Module):
    def __init__(self, cat_dims, num_features_dim, emb_dims=None, hidden_dims=[128, 64, 32], dropout=0.2):
        super().__init__()
        if emb_dims is None:
            emb_dims = [min(50, (dim + 1) // 2) for dim in cat_dims]
            
        self.embeddings = nn.ModuleList([
            nn.Embedding(num_embeddings=dim, embedding_dim=emb_dim)
            for dim, emb_dim in zip(cat_dims, emb_dims)
        ])
        
        total_emb_dim = sum(emb_dims)
        self.num_bn = nn.BatchNorm1d(num_features_dim)
        
        input_dim = total_emb_dim + num_features_dim
        
        layers = []
        for h_dim in hidden_dims:
            layers.append(nn.Linear(input_dim, h_dim))
            layers.append(nn.BatchNorm1d(h_dim))
            layers.append(nn.ReLU())
            layers.append(nn.Dropout(dropout))
            input_dim = h_dim
            
        layers.append(nn.Linear(input_dim, 1))
        self.net = nn.Sequential(*layers)
        
    def forward(self, cat_features, num_features):
        emb_outputs = []
        for i, emb in enumerate(self.embeddings):
            emb_outputs.append(emb(cat_features[:, i]))
            
        x_emb = torch.cat(emb_outputs, dim=1)
        x_num = self.num_bn(num_features)
        
        x = torch.cat([x_emb, x_num], dim=1)
        return self.net(x)

