# =====================================================================
# Utilities
# =====================================================================

def load_sql(query: str, dtypes: Dict[str, Any] = None) -> pd.DataFrame:
    """Executes a SQL query and returns a DataFrame."""
    conn = postgres_connection()
    try:
        df = pd.read_sql(query, conn, dtype=dtypes)
    except Exception as e:
        raise RuntimeError(f"Error in load_sql: {e}\nQuery: {query}")
    finally:
        conn.close()
    return df

def load_model(model_version: str = "default") -> Any:
    """
    Loads the ML model from a pickle file.
    """
    if os.environ.get("IS_LMS", "0") == "1":
        models_dir = os.environ.get("MODELS_DIR", ".")
    else:
        models_dir = "."

    model_filename = f"model_{model_version}.pkl"
    model_path = os.path.join(models_dir, model_filename)

    logger.info(f"Loading model version '{model_version}' from {model_path}...")

    try:
        with open(model_path, "rb") as file:
            model = pickle.load(file)
    except FileNotFoundError:
        raise FileNotFoundError(f"❌ Model version '{model_version}' file not found: {model_path}")
    except Exception as e:
        raise RuntimeError(f"❌ Error loading model version '{model_version}': {e}") from e

    logger.success(f"Model version '{model_version}' successfully loaded")

    return model

def get_exp_group(user_id: int) -> str:
    """Determines the user group for A/B testing (50/50 split)."""
    value_str = str(user_id) + SALT
    hash_val = int(hashlib.md5(value_str.encode()).hexdigest(), 16)
    if hash_val % 100 < SPLIT_RATIO:
        return 'test'
    else:
        return 'control'


