logger.info("Starting initialization of A/B Testing Recommendation Service...")

app = FastAPI()

# 1. Load models
model_control = load_model("control")
model_test = load_model("test")

# 2. Reconstruct PyTorch model for test group
logger.info("Reconstructing PyTorch model for the test group...")
try:
    decoded = base64.b64decode(MODEL_DATA_B64.strip().encode('ascii'))
    decompressed = gzip.decompress(decoded)
    checkpoint = pickle.loads(decompressed)
    
    pytorch_preprocessors = checkpoint["preprocessors"]
    pytorch_model = RecommenderNet(
        cat_dims=pytorch_preprocessors["cat_dims"],
        num_features_dim=pytorch_preprocessors["num_features_dim"],
        hidden_dims=[256, 128, 64]
    )
    state_dict = {k: torch.tensor(v) for k, v in checkpoint["state_dict"].items()}
    pytorch_model.load_state_dict(state_dict)
    pytorch_model.eval()
    logger.success("PyTorch model successfully reconstructed")
except Exception as e:
    logger.error(f"Error reconstructing PyTorch model: {e}")
    raise e

def custom_predict_proba(X: pd.DataFrame):
    X_df = X.copy()
    
    cat_arr = []
    for col in pytorch_preprocessors['cat_cols']:
        mapping = pytorch_preprocessors['le_mappings'][col]
        unknown_idx = len(mapping)
        X_df[col] = X_df[col].astype(str).map(mapping).fillna(unknown_idx).astype(np.int64)
        cat_arr.append(X_df[col].values)
    cat_arr = np.column_stack(cat_arr)
    
    num_arr = []
    user_behavior_cols = {'user_total_views', 'user_total_likes', 'user_ctr'}.union({(f'user_factor_{i}' for i in range(1, 11))}).union({(f'user_emb_{i}' for i in range(32))})
    post_behavior_cols = {'post_total_views', 'post_total_likes', 'post_ctr'}.union({(f'post_factor_{i}' for i in range(1, 11))}).union({(f'post_emb_{i}' for i in range(32))})
    
    is_user_missing = (X_df['user_total_views'] == 0).values
    is_post_missing = (X_df['post_total_views'] == 0).values
    
    for col in pytorch_preprocessors['num_cols']:
        mean = pytorch_preprocessors['col_mean'][col]
        scale = pytorch_preprocessors['col_scale'][col]
        
        scaled_vals = (X_df[col].values.astype(np.float32) - mean) / scale
        
        if col in user_behavior_cols:
            scaled_vals = np.where(is_user_missing, 0.0, scaled_vals)
        elif col in post_behavior_cols:
            scaled_vals = np.where(is_post_missing, 0.0, scaled_vals)
            
        num_arr.append(scaled_vals)
    num_arr = np.column_stack(num_arr)
    
    cat_tensor = torch.tensor(cat_arr, dtype=torch.long)
    num_tensor = torch.tensor(num_arr, dtype=torch.float32)
    
    with torch.no_grad():
        logits = pytorch_model(cat_tensor, num_tensor).squeeze(1)
        probs = torch.sigmoid(logits).numpy()
        
    probas = np.zeros((len(X), 2))
    probas[:, 0] = 1.0 - probs
    probas[:, 1] = probs
    return probas

model_test.predict_proba = custom_predict_proba

# 3. Load features
logger.info("Loading base post features...")
post_features_base = load_sql("SELECT * FROM public.seyfetdinov_post_features")

logger.info("Loading post texts and topics...")
post_texts = load_sql("SELECT post_id, text, topic FROM public.post_text_df")
post_features_ml = post_features_base.merge(post_texts, on=['post_id', 'topic'])

logger.info("Loading post embeddings from database (for DL)...")
post_emb = load_sql("SELECT * FROM public.post_embeddings")
post_emb = post_emb.rename(columns={f'emb_{i}': f'post_emb_{i}' for i in range(32)})
post_features_dl = post_features_ml.merge(post_emb, on='post_id', how='left').fillna(0)

logger.info("Loading user features...")
user_features_base = load_sql("SELECT * FROM public.seyfetdinov_user_features")
user_features_ml = user_features_base.set_index('user_id')

logger.info("Loading user embeddings from database (for DL)...")
user_emb = load_sql("SELECT * FROM public.user_embeddings")
user_emb = user_emb.rename(columns={f'emb_{i}': f'user_emb_{i}' for i in range(32)})
user_features_dl = user_features_base.merge(user_emb, on='user_id', how='left').fillna(0).set_index('user_id')

logger.success("Service warmed up and ready to serve recommendations")


# =====================================================================
# Recommendation Functions
# =====================================================================

def get_recommendations_control(user_id: int, dt: datetime, limit: int) -> List[PostGet]:
    """ML (CatBoost) recommendations for the control group."""
    if user_id not in user_features_ml.index:
        logger.warning(f"User {user_id} not found in ML features.")
        return []
    
    user_f = user_features_ml.loc[user_id]
    X = post_features_ml.copy()
    
    for col in user_f.index:
        X[col] = user_f[col]
        
    X['hour'] = dt.hour
    X['day_of_week'] = dt.weekday()
    
    predict_df = X[ML_MODEL_COLUMNS]
    probas = model_control.predict_proba(predict_df)[:, 1]
    
    X['prob'] = probas
    top_posts = X.sort_values('prob', ascending=False).head(limit)
    
    recs = []
    for _, row in top_posts.iterrows():
        recs.append(
            PostGet(
                id=int(row['post_id']),
                text=row['text'],
                topic=row['topic']
            )
        )
    return recs


def get_recommendations_test(user_id: int, dt: datetime, limit: int) -> List[PostGet]:
    """DL (PyTorch) recommendations for the test group."""
    if user_id not in user_features_dl.index:
        logger.warning(f"User {user_id} not found in DL features.")
        return []
    
    user_f = user_features_dl.loc[user_id]
    X = post_features_dl.copy()
    
    for col in user_f.index:
        X[col] = user_f[col]
        
    X['hour'] = dt.hour
    X['day_of_week'] = dt.weekday()
    
    predict_df = X[DL_MODEL_COLUMNS]
    probas = model_test.predict_proba(predict_df)[:, 1]
    
    X['prob'] = probas
    top_posts = X.sort_values('prob', ascending=False).head(limit)
    
    recs = []
    for _, row in top_posts.iterrows():
        recs.append(
            PostGet(
                id=int(row['post_id']),
                text=row['text'],
                topic=row['topic']
            )
        )
    return recs


# =====================================================================
# API Endpoints
# =====================================================================

@app.get("/post/recommendations/", response_model=Response)
def recommended_posts(user_id: int, dt: datetime, limit: int = 5) -> Response:
    """
    Endpoint for A/B testing recommendation service.
    """
    exp_group = get_exp_group(user_id)
    
    if exp_group == 'control':
        logger.info(f"User {user_id} mapped to control group. Using model_control (CatBoost).")
        recommendations = get_recommendations_control(user_id, dt, limit)
    elif exp_group == 'test':
        logger.info(f"User {user_id} mapped to test group. Using model_test (PyTorch).")
        recommendations = get_recommendations_test(user_id, dt, limit)
    else:
        raise ValueError("Unknown group")
        
    return Response(exp_group=exp_group, recommendations=recommendations)
